INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a5120d7e-57e8-4d8a-96ca-59b4c015f50e',
  '00000000-0000-0000-0000-000000000001',
  $escape$SwiftUI — Creating Custom Share Extensions$escape$,
  $escape$To create a custom share extension in SwiftUI, you'll need to define a `@main` class that conforms to `UIAppSceneSessionRoleHandler` and `UIUserActivityDelegate`. This class must be declared in a separate target within your Xcode project. The `UIUserActivity` delegate method `userActivity(_:restoringUserActivityReturning:error:)` is used to handle incoming user activity. For example:$escape$,
  $escape$import SwiftUI
@main
struct MyShareExtension: App {
    var body: some Scene {
        WindowGroup {
            Text("Share Extension")
        }
    }
}
extension MyApp: UIUserActivityDelegate {
    func userActivity(_ userActivity: NSUserActivity,
                       restoringUserActivityReturning:error: NSErrorPointer) -> Bool {
        // Handle user activity
        // Return true to indicate success
        return true
    }
}$escape$,
  $escape$swift$escape$,
